        checkpoints: [],
      },
    },
    performance: {
      metrics: new Map(),
      bottlenecks: [],
      optimizations: [],
    },
    ...overrides,
  };
}

function createMockHook(overrides?: Partial<HookRegistration>): HookRegistration {
  return {
    id: 'test-hook',
    type: 'workflow-step',
    handler: async () => ({ continue: true }),
    priority: 10,
    ...overrides,
  };
}

// ===== Tests =====

describe('HookMatcher', () => {
