      await controller.processQueuedCommands('query-1');

      expect(mockQuery.interrupt).toHaveBeenCalled();
    });
  });

  describe('Monitoring', () => {
    it('should emit status updates during monitoring', (done) => {
      const mockQuery = {
        interrupt: vi.fn(),
