  private async createTables(): Promise<void> {
    const tables = [
      // Swarms table
      `CREATE TABLE IF NOT EXISTS swarms (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        topology TEXT NOT NULL,
        max_agents INTEGER DEFAULT 8,
        strategy TEXT DEFAULT 'balanced',
        status TEXT DEFAULT 'initializing',
        config TEXT,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
        destroyed_at TEXT
      )`,

      // Agents table
      `CREATE TABLE IF NOT EXISTS agents (
        id TEXT PRIMARY KEY,
        swarm_id TEXT NOT NULL,
        type TEXT NOT NULL,
        name TEXT,
        status TEXT DEFAULT 'spawning',
        capabilities TEXT,
        config TEXT,
        metadata TEXT,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
        terminated_at TEXT,
        FOREIGN KEY (swarm_id) REFERENCES swarms(id)
      )`,

      // Tasks table
      `CREATE TABLE IF NOT EXISTS tasks (
        id TEXT PRIMARY KEY,
        swarm_id TEXT NOT NULL,
        description TEXT NOT NULL,
        priority TEXT DEFAULT 'medium',
        strategy TEXT DEFAULT 'adaptive',
        status TEXT DEFAULT 'pending',
        max_agents INTEGER,
        requirements TEXT,
        metadata TEXT,
        result TEXT,
        error_message TEXT,
        assigned_to TEXT,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP,
        started_at TEXT,
        completed_at TEXT,
        FOREIGN KEY (swarm_id) REFERENCES swarms(id)
      )`,

      // Performance metrics table
      `CREATE TABLE IF NOT EXISTS performance_metrics (
        id TEXT PRIMARY KEY,
        swarm_id TEXT,
        agent_id TEXT,
        metric_type TEXT NOT NULL,
        metric_name TEXT NOT NULL,
        metric_value REAL NOT NULL,
        unit TEXT,
        timestamp TEXT DEFAULT CURRENT_TIMESTAMP,
        metadata TEXT
      )`,

      // Events table
      `CREATE TABLE IF NOT EXISTS events (
        id TEXT PRIMARY KEY,
        swarm_id TEXT,
        agent_id TEXT,
        event_type TEXT NOT NULL,
        event_name TEXT NOT NULL,
        event_data TEXT,
        severity TEXT DEFAULT 'info',
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
      )`,
    ];

    for (const table of tables) {
      await this.execute(table);
    }
  }

  private async query(sql: string, params: any[] = []): Promise<any[]> {
    if (this.config.type === 'sqlite') {
      const stmt = this.db.prepare(sql);
      return stmt.all(...params);
    }

    // Other database types would be handled here
    throw new DatabaseError('Unsupported database operation');
